// 1. Configuration
const destinationChannels = [
 '-1111111111111',
  '-2222222222222',
  '-3333333333333',
  '-4444444444444',
  '-5555555555555'
];

const targetDomainRegex = /example\.com/i; // Case-insensitive
const now = Date.now();
const limit = now - (24 * 60 * 60 * 1000); // Last 24 Hours

// === FILTER LOGIC (Updated for new input) ===
const filteredItems = items.filter(i => {
  // Support both old n8n style ({json: ...}) aur new flat style
  const data = i.json || i;
  if (!data) return false;

  // --- AUTO-DETECT KEYS (new structure ke hisab se) ---
  const msgId = data.messageId || data.id || data.message_id || data.msg_id;
  const msgText = data.message || data.text || data.caption || data.rawMessage || "";
  const msgDateStr = data.date;                    // ab ISO string hai
  const isOut = data.isOutgoing ?? data.out ?? false;

  // --- VALIDATION CHECKS ---
  // ID Check
  if (!msgId || (typeof msgId === 'string' && msgId.trim() === "")) return false;

  // Time Check (ISO string handle kiya)
  let msgTimestamp = 0;
  if (typeof msgDateStr === 'string' && msgDateStr.includes('T')) {
    msgTimestamp = new Date(msgDateStr).getTime();
  } else if (typeof msgDateStr === 'number') {
    msgTimestamp = msgDateStr * 1000;
  }

  if (!msgTimestamp || msgTimestamp <= limit) return false;

  // Outgoing skip (sirf User ke replay messages rakhna hai)
  if (isOut === true) return false;

  // Example.com link check
  if (!targetDomainRegex.test(msgText)) return false;

  return true;
});

// === ROUND ROBIN DISTRIBUTION ===
return filteredItems.map((item, index) => {
  const data = item.json || item;   // same support

  const channelIndex = index % destinationChannels.length;

  // Updated field mapping
  const finalMsgId   = data.messageId || data.id || data.message_id || data.msg_id || '';
  const finalSrcName = data.senderName || data.sourceName || data.Source_Name || data.chatName || 'Unknown';
  const finalChatId  = data.chatId || data.sourceId || data.chat_id || data.senderId || '';
  const finalText = data.message || data.rawMessage || data.text || data.caption || "";
  const finalDate    = data.humanDate || data.human_date || data.date || "";
  const finalHasMedia = data.hasMedia ?? data.has_media ?? false;
  const finalMediaType = data.messageType || data.mediaType || data.media_type || null;

  return {
    json: {
      message_id: String(finalMsgId),
      Source_Name: String(finalSrcName),
      sourceId: String(finalChatId),
      DestinationID: destinationChannels[channelIndex],
      text: finalText,
      humanDate: finalDate,
      hasMedia: finalHasMedia,
      mediaType: finalMediaType,
      match_found: true,
      original_index: index
    }
  };
});

return items.filter(i => {
  const msgId = i.json.id || i.json.message_id;
  const srcId = i.json.sourceId;
  const destId = i.json.DestinationID;
  return (msgId && srcId && destId);
}).map(i => {
  const data = i.json;
  return {
    json: {
      message_id: String(data.message_id),
      SourceID: String(data.sourceId),
      DestinationID: String(data.DestinationID),
      text: data.text || null
    }
  };
});

